module frequency_divider(
  input clk_in,
  input rst_n,
  output reg clk_out
);

  reg [1:0] obf_counter;

  always @(posedge clk_in or negedge rst_n) begin
    if (~rst_n) begin
      obf_counter <= 2'b00;
      clk_out <= 0;
    end
    else begin
      obf_counter <= obf_counter + 1;
      if (obf_counter == 2'b11) begin
        clk_out <= ~clk_out;
        obf_counter <= 2'b00;
      end
    end
  end

endmodule
